const t={macroDesigner:{intro:{t:0,b:{t:2,i:[{t:3}],s:"离线模拟 G-code —— 粘贴或编写程序，即可查看工具头路径、包围盒、移动与挤出总量以及时间估算，全程无需连接打印机。还可浏览内置宏库作为参考。"}},help:{guide:{t:0,b:{t:2,i:[{t:3}],s:"帮助"}},guideTitle:{t:0,b:{t:2,i:[{t:3}],s:"关于宏设计器"}},close:{t:0,b:{t:2,i:[{t:3}],s:"关闭"}},howToRead:{t:0,b:{t:2,i:[{t:3}],s:"使用方法"}},steps:[{t:0,b:{t:2,i:[{t:3}],s:"在编辑器中输入或粘贴 G-code（初始已加载一个示例方形）。"}},{t:0,b:{t:2,i:[{t:3}],s:"点击“模拟”——二维路径和统计数据随即更新。"}},{t:0,b:{t:2,i:[{t:3}],s:"实线为挤出移动；浅色虚线为空驶移动。"}},{t:0,b:{t:2,i:[{t:3}],s:"浏览宏库并“插入”一个，以其命令为起点开始编写。"}}],topics:{simulator:{title:{t:0,b:{t:2,i:[{t:3}],s:"模拟器"}},body:{t:0,b:{t:2,i:[{t:3}],s:"它在虚拟工具头上运行程序：G0/G1 移动、G90/G91（绝对/相对）、M82/M83（挤出机模式）、G92（设置坐标）以及 G28（回零 → 原点）。它会报告路径、包围盒、移动与挤出总量、根据进给速度得出的粗略时间估算，以及逐命令的时间线。任何内容都不会发送到打印机。"}}},motion:{title:{t:0,b:{t:2,i:[{t:3}],s:"路径与时间"}},body:{t:0,b:{t:2,i:[{t:3}],s:"二维视图为 XY 路径（Z 包含在包围盒中）。时间估算用每段移动的长度除以其进给速度——它忽略了加速度，因此只是一个粗略的下限，并非确切的打印时间。模拟器无法建模的命令（例如 M-codes、高级宏）会作为警告列出并被跳过。"}}},macros:{title:{t:0,b:{t:2,i:[{t:3}],s:"宏库"}},body:{t:0,b:{t:2,i:[{t:3}],s:"一组常用 Klipper 宏的参考集合，包含名称、功能说明及其所需的配置节。“插入”会将一个宏的高级命令放入编辑器作为起点——请注意这些命令在打印机上会进一步展开（完整的 Jinja/宏展开功能即将推出）。"}}},glossary:{title:{t:0,b:{t:2,i:[{t:3}],s:"术语表"}},body:{t:0,b:{static:"",t:2,i:[]}}}},glossary:{gcode:{term:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},def:{t:0,b:{t:2,i:[{t:3}],s:"打印机逐行运行的运动语言（移动、温度、风扇……）。"}}},feedrate:{term:{t:0,b:{t:2,i:[{t:3}],s:"进给速度 (F)"}},def:{t:0,b:{t:2,i:[{t:3}],s:"以 mm/min 表示的移动速度——F1200 即 20 mm/s。决定每段移动的运行速度。"}}},macro:{term:{t:0,b:{t:2,i:[{t:3}],s:"宏"}},def:{t:0,b:{t:2,i:[{t:3}],s:"一个具名、可复用的命令（例如 QUAD_GANTRY_LEVEL），可展开为一系列 G-code。"}}}}},editor:{label:{t:0,b:{t:2,i:[{t:3}],s:"G-code"}},simulate:{t:0,b:{t:2,i:[{t:3}],s:"模拟"}},simulating:{t:0,b:{t:2,i:[{t:3}],s:"模拟中…"}},sample:{t:0,b:{t:2,i:[{t:3}],s:"加载示例"}},clear:{t:0,b:{t:2,i:[{t:3}],s:"清空"}}},library:{label:{t:0,b:{t:2,i:[{t:3}],s:"内置宏"}},placeholder:{t:0,b:{t:2,i:[{t:3}],s:"浏览宏…"}},insert:{t:0,b:{t:2,i:[{t:3}],s:"插入到编辑器"}},requires:{t:0,b:{t:2,i:[{t:3,v:"需要："},{t:4,k:"sections"}]}},none:{t:0,b:{t:2,i:[{t:3}],s:"—"}}},result:{title:{t:0,b:{t:2,i:[{t:3}],s:"模拟"}},moves:{t:0,b:{t:2,i:[{t:4,k:"count"},{t:3,v:" 段移动"}]}},distance:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm 空驶"}]}},extrude:{t:0,b:{t:2,i:[{t:4,k:"mm"},{t:3,v:" mm 挤出"}]}},time:{t:0,b:{t:2,i:[{t:3,v:"约 "},{t:4,k:"s"},{t:3,v:" 秒"}]}},bounds:{t:0,b:{t:2,i:[{t:3}],s:"包围盒"}},empty:{t:0,b:{t:2,i:[{t:3}],s:"没有可模拟的移动。"}}},path:{title:{t:0,b:{t:2,i:[{t:3}],s:"工具头路径 (XY)"}},noPath:{t:0,b:{t:2,i:[{t:3}],s:"运行一次模拟即可查看路径。"}}},timeline:{title:{t:0,b:{t:2,i:[{t:3}],s:"时间线"}},line:{t:0,b:{t:2,i:[{t:3}],s:"行号"}},cmd:{t:0,b:{t:2,i:[{t:3}],s:"命令"}},action:{t:0,b:{t:2,i:[{t:3}],s:"动作"}}},warnings:{title:{t:0,b:{t:2,i:[{t:3}],s:"警告"}}},explain:{title:{t:0,b:{t:2,i:[{t:3}],s:"解释此宏"}},travel:{t:0,b:{t:2,i:[{t:3,v:"快速移动到 X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:"，速度 "},{t:4,k:"f"},{t:3,v:" mm/min"}]}},print:{t:0,b:{t:2,i:[{t:3,v:"打印移动 — 在 "},{t:4,k:"d"},{t:3,v:" mm 内挤出 "},{t:4,k:"e"},{t:3,v:" mm 到 X"},{t:4,k:"x"},{t:3,v:" Y"},{t:4,k:"y"},{t:3,v:"，速度 "},{t:4,k:"f"},{t:3,v:" mm/min"}]}},retract:{t:0,b:{t:2,i:[{t:3,v:"回抽 "},{t:4,k:"e"},{t:3,v:" mm"}]}},prime:{t:0,b:{t:2,i:[{t:3,v:"原地挤出 "},{t:4,k:"e"},{t:3,v:" mm"}]}},noMove:{t:0,b:{t:2,i:[{t:3}],s:"无移动"}},absXYZ:{t:0,b:{t:2,i:[{t:3}],s:"切换到绝对定位 (G90)"}},relXYZ:{t:0,b:{t:2,i:[{t:3}],s:"切换到相对定位 (G91)"}},absE:{t:0,b:{t:2,i:[{t:3}],s:"切换到绝对挤出 (M82)"}},relE:{t:0,b:{t:2,i:[{t:3}],s:"切换到相对挤出 (M83)"}},setPos:{t:0,b:{t:2,i:[{t:3}],s:"设置当前位置 (G92)"}},home:{t:0,b:{t:2,i:[{t:3}],s:"回零各轴 (G28) → 原点"}},abs:{t:0,b:{t:2,i:[{t:3}],s:"绝对"}},rel:{t:0,b:{t:2,i:[{t:3}],s:"相对"}},cum:{t:0,b:{t:2,i:[{t:3,v:"累计："},{t:4,k:"d"},{t:3,v:" mm · "},{t:4,k:"e"},{t:3,v:" mm · ~"},{t:4,k:"s"},{t:3,v:" s"}]}},note:{t:0,b:{t:2,i:[{t:3}],s:"含未解析表达式或 Jinja 控制流的行不会被模拟，此处略去。"}}}}};export{t as default};
